svg.script:
(function () {
  var svg = document.documentElement;
  svg._chartInit = function (svgEl, ctx) {
var svg         = document.getElementById('root');
  var dataLayerEl = document.getElementById('data-layer');
  var stages = Array.prototype.slice.call(dataLayerEl.querySelectorAll('.fstage'));

  /* Ã‚Â§2 Ã¢â‚¬â€ isDark declared before all other code */

  /* Ã‚Â§3 Ã¢â‚¬â€ Method A1: animationend + .visible, adaptive stagger, .ready gate */
  var duration = 0.8;
  var stagger  = Math.min(0.25, 1.0 / stages.length);
  var lastDelay = 0;

  stages.forEach(function(g, i) {
    var delay = (i * stagger).toFixed(2);
    if (parseFloat(delay) > lastDelay) lastDelay = parseFloat(delay);
    g.style.animation = 'stageFade ' + duration + 's ease-out ' + delay + 's';
    g.addEventListener('animationend', function() {
      g.style.animation = '';
      g.classList.add('visible');
    }, { once: true });
  });

  setTimeout(function() {
    dataLayerEl.classList.add('ready');
  }, (lastDelay + duration + 0.1) * 1000);

  /* Ã‚Â§5 Ã¢â‚¬â€ JS-driven tooltip */
  var tip    = document.getElementById('tip');
  var tipBg  = document.getElementById('tip-bg');
  var tipBdr = document.getElementById('tip-bdr');
  var tipArr = document.getElementById('tip-arr');
  var tipVal = document.getElementById('tip-val');
  var tipLbl = document.getElementById('tip-lbl');
  var tipPct = document.getElementById('tip-pct');
  var BH = 62, TAIL = 10, RX = 9, TW = 8;

  function posTip(cx, cy, name, val, pct, dropoff) {
    /* 1 Ã¢â‚¬â€ set text first so getBBox measures real widths */
    tipVal.textContent = val;
    tipLbl.textContent = name;
    tipPct.textContent = pct + (dropoff ? '  Ã‚Â·  ' + dropoff : '');

    /* 2 Ã¢â‚¬â€ measure, derive hw */
    var pad = 20;
    var hw = Math.max(
      tipVal.getBBox().width + pad,
      tipLbl.getBBox().width + pad,
      tipPct.getBBox().width + pad,
      60
    ) / 2;

    /* 3 Ã¢â‚¬â€ clamp tx */
    var tx = Math.max(hw + 8, Math.min(cx, 1100 - hw - 8));

    /* 4 Ã¢â‚¬â€ flip: bubble below when near top */
    var flip = cy < BH + TAIL + 20;
    var bT = flip ? cy + TAIL      : cy - TAIL - BH;
    var bB = flip ? cy + TAIL + BH : cy - TAIL;
    if (bT < 8)   { bT = 8;   bB = bT + BH; }
    if (bB > 610) { bB = 610; bT = bB - BH; }
    var bL = tx - hw, bR = tx + hw;

    /* 5 Ã¢â‚¬â€ background rect */
    tipBg.setAttribute('x', bL);      tipBg.setAttribute('y', bT);
    tipBg.setAttribute('width', hw*2); tipBg.setAttribute('height', BH);

    /* 6 Ã¢â‚¬â€ open border path + tail */
    var openD, tailD;
    if (!flip) {
      openD = 'M'+(tx+TW)+','+bB+
        ' L'+(bR-RX)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-RX)+
        ' L'+bR+','+(bT+RX)+' Q'+bR+','+bT+' '+(bR-RX)+','+bT+
        ' L'+(bL+RX)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+RX)+
        ' L'+bL+','+(bB-RX)+' Q'+bL+','+bB+' '+(bL+RX)+','+bB+
        ' L'+(tx-TW)+','+bB;
      tailD = 'M'+(tx-TW)+','+bB+' L'+tx+','+(bB+TAIL)+' L'+(tx+TW)+','+bB;
    } else {
      openD = 'M'+(tx-TW)+','+bT+
        ' L'+(bL+RX)+','+bT+' Q'+bL+','+bT+' '+bL+','+(bT+RX)+
        ' L'+bL+','+(bB-RX)+' Q'+bL+','+bB+' '+(bL+RX)+','+bB+
        ' L'+(bR-RX)+','+bB+' Q'+bR+','+bB+' '+bR+','+(bB-RX)+
        ' L'+bR+','+(bT+RX)+' Q'+bR+','+bT+' '+(bR-RX)+','+bT+
        ' L'+(tx+TW)+','+bT;
      tailD = 'M'+(tx+TW)+','+bT+' L'+tx+','+(bT-TAIL)+' L'+(tx-TW)+','+bT;
    }
    tipBdr.setAttribute('d', openD);
    tipArr.setAttribute('d', tailD);

    /* 7 Ã¢â‚¬â€ text positions */
    tipVal.setAttribute('x', tx); tipVal.setAttribute('y', bT + BH * 0.26);
    tipLbl.setAttribute('x', tx); tipLbl.setAttribute('y', bT + BH * 0.52);
    tipPct.setAttribute('x', tx); tipPct.setAttribute('y', bT + BH * 0.78);
  }

  /* Ã‚Â§4 Ã¢â‚¬â€ Hover: A1 pattern, container mouseleave (adjacent trapezoids) */
  stages.forEach(function(g) {
    g.addEventListener('mouseenter', function() {
      dataLayerEl.classList.add('hovering');
      stages.forEach(function(s) { s.classList.remove('hovered'); });
      g.classList.add('hovered');
      tip.style.opacity = '1';
      var cx      = parseFloat(g.getAttribute('data-cx'));
      var cy      = parseFloat(g.getAttribute('data-cy'));
      var name    = g.getAttribute('data-name');
      var val     = g.getAttribute('data-val');
      var pct     = g.getAttribute('data-pct');
      var dropoff = g.getAttribute('data-dropoff');
      posTip(cx, cy, name, val, pct, dropoff);
    });
    g.addEventListener('mouseleave', function() {
      g.classList.remove('hovered');
      tip.style.opacity = '';
    });
  });

  /* container mouseleave for .hovering Ã¢â‚¬â€ prevents flicker between adjacent trapezoids */
  dataLayerEl.addEventListener('mouseleave', function() {
    dataLayerEl.classList.remove('hovering');
  });

  /* Ã‚Â§2 Ã¢â‚¬â€ Dark mode toggle */
  };
  if (window.bootstrapChart) { window.bootstrapChart(svg); }
}());
